def log_call(func):
    def wrapper():
        print(f'Calling {func.__name__}')
        func()
        print(f'Finished {func.__name__}')
    return wrapper

@log_call
def say_hello():
    print('Hello!')

say_hello()

def execute_twice(func):
    def wrapper(*args, **kwargs):
        func(*args, **kwargs)
        return func(*args, **kwargs)
    return wrapper

@execute_twice
def greet(name):
    print(f'Welcome, {name}')

greet('Alice')

def repeat(num_times):
    def decorator_repeat(func):
        def wrapper(*args, **kwargs):
            for _ in range(num_times):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator_repeat

@repeat(num_times=3)
def echo(msg):
    print(msg)

echo('Echo!')

import time
from functools import wraps

def timer(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'{func.__name__} took {end-start:.4f} secs')
        return result
    return wrapper

@timer
def slow_task():
    """Simulates a slow task."""
    time.sleep(1)

slow_task()
print(slow_task.__doc__)

