def validate_positive(func):
    def wrapper(*args, **kwargs):
        if any(x <= 0 for x in args) or any(x <= 0 for x in kwargs.values()):
            raise ValueError('All arguments must be positive.')
        return func(*args, **kwargs)
    return wrapper
